func TestEncodeDecodeWorkspaceSetLayoutRequest(t *testing.T) {
	v := WorkspaceSetLayoutRequest{}
	var buf bytes.Buffer
	msgp.Encode(&buf, &v)

	m := v.Msgsize()
	if buf.Len() > m {
		t.Log("WARNING: TestEncodeDecodeWorkspaceSetLayoutRequest Msgsize() is inaccurate")
	}

	vn := WorkspaceSetLayoutRequest{}
	err := msgp.Decode(&buf, &vn)
	if err != nil {
		t.Error(err)
	}

	buf.Reset()
	msgp.Encode(&buf, &v)
	err = msgp.NewReader(&buf).Skip()
	if err != nil {
		t.Error(err)
	}
}

